cat >/home/ctfplayer/read_qr.py <<'EOF'
from pyzbar.pyzbar import decode
from PIL import Image

# Try both normal and inverted images
try:
    # Try normal image
    img = Image.open('qr_final.png')
    decoded_objects = decode(img)
    if decoded_objects:
        print("Normal image decoded:")
        for obj in decoded_objects:
            print(obj.data.decode())
except Exception as e:
    print(f"Error with normal image: {e}")

try:
    # Try inverted image
    img = Image.open('qr_final_inv.png')
    decoded_objects = decode(img)
    if decoded_objects:
        print("Inverted image decoded:")
        for obj in decoded_objects:
            print(obj.data.decode())
except Exception as e:
    print(f"Error with inverted image: {e}")
EOF

